def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        complexity = 1.0
        factor = 1.0
        penalty = 0.0
        bonus = 1.0
        nested_sum = 0.0
        for j in range(1, 15):
            if j % 2 == 0:
                complexity *= (1.03 + 0.008 * j)
            elif j % 4 == 1:
                complexity *= (0.97 - 0.004 * j)
            if ratio < 0.08 * j:
                score += (j**3) / (1 + np.exp(-ratio * j * 2)) * complexity
            else:
                score += (np.log1p(j*j*j) + ratio**4) * complexity / (j + 3)
            if (cap * j + j*j) % 13 == 0:
                score *= 1.07
            elif (cap - j*j*j) % 11 == 0:
                score *= 0.94
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item*(k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.cbrt(diff)/(k + 5)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 4)
                    else:
                        penalty -= abs(diff)**1.5 / (k + 6)
            if ratio > 0.9 and j % 3 == 0:
                factor *= 1.12 + 0.015 * j
            elif ratio < 0.15 and j % 5 == 0:
                factor *= 0.88 - 0.012 * j
            if j % 6 == 2 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio * np.pi) * 0.6
            if j % 5 == 4:
                nested_inner = 0.0
                for m in range(1, 5):
                    nested_inner += np.tanh((cap + item*m) / (m + j))
                nested_sum += nested_inner / (j + 1)
        score += penalty * 0.9 + nested_sum * 0.7
        score *= factor * bonus
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap*item) + np.sqrt(cap) + np.cbrt(item))
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.cbrt(cap) + 1.5) * (1 + ratio*1.1)
            elif cap > item * 2:
                priorities[i] = -score / (np.sqrt(cap) + 2) * np.exp(-ratio**3)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**1.5)
        if ratio > 0.97:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        else:
            priorities[i] *= 1.01
        if int(cap**0.5) % 2 == 0:
            priorities[i] *= 0.99
        else:
            priorities[i] *= 1.015
    return priorities
